request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org2 ?org2Id ?countModels WHERE {
  {
    SELECT (COUNT(DISTINCT ?m0) AS ?countModels) WHERE {
      ?org0 a bboExt:Organization ;
            tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" ;
            tai:belongsTo ?corp0 .
      ?m0 a bboExt:Model ;
          tai:belongsTo ?org0 .
    }
  }

  ?org2 a bboExt:Organization ;
        tai:organizationId ?org2Id ;
        tai:belongsTo ?corp1 .
  ?m a bboExt:Model ;
      tai:belongsTo ?org2 .

  {
    SELECT ?org2 (COUNT(DISTINCT ?m) AS ?countModels) WHERE {
      ?org2 a bboExt:Organization ;
            tai:belongsTo ?corp1 .
      ?m a bboExt:Model ;
         tai:belongsTo ?org2 .
    }
    GROUP BY ?org2
  }
}
ORDER BY ?org2Id
LIMIT 25
